mapper.select:
SELECT c.coupon_id AS couponId, c.title, c.amount, c.min_amount AS minAmount, c.start_time AS startTime, c.end_time AS endTime, c.status, COALESCE(c.total_stock, 0) AS totalStock, COALESCE(c.remaining_stock, 0) AS remainingStock, COALESCE(c.receive_count, 0) AS receiveCount, COALESCE(c.per_user_limit, 1) AS perUserLimit, 1 AS received, uc.user_coupon_id AS userCouponId, uc.status AS userCouponStatus, uc.order_id AS orderId, uc.receive_time AS receiveTime, uc.use_time AS useTime, CASE WHEN uc.status = 0 AND c.status = 1 AND NOW() BETWEEN c.start_time AND c.end_time THEN 1 ELSE 0 END AS available FROM user_coupon uc INNER JOIN coupon c ON uc.coupon_id = c.coupon_id WHERE uc.user_id = #{userId}
AND uc.status = #{status}
ORDER BY uc.status ASC, c.end_time ASC, uc.receive_time DESC

SELECT COUNT(1)
FROM user_coupon
WHERE user_id = #{userId}
  AND coupon_id = #{couponId}
